// กลุ่มกฎตามประเภท
export const RULES_BY_TYPE: Record<string, DetectionRuleDef[]> = DETECTION_RULES.reduce(
  (acc, rule) => {
    if (!acc[rule.fallacyType]) acc[rule.fallacyType] = [];
    acc[rule.fallacyType].push(rule);
    return acc;
  },
  {} as Record<string, DetectionRuleDef[]>,
);
